    atsKeywords: ['forklift operation', 'forklift certified', 'powered industrial truck', 'reach truck', 'order picker', 'pallet jack', 'counterbalance forklift', 'rough terrain forklift', 'OSHA forklift', 'material handling', 'warehouse operations'],
