    relatedSkills: ['troubleshooting', 'lockout-tagout', 'electrical-wiring', 'plumbing-systems', 'hvac-systems', 'safety-protocols', 'power-tools', 'hand-tools'],
    professionSlugs: ['maintenance-technician', 'plant-manager', 'hvac-technician', 'diesel-mechanic', 'manufacturing-engineer', 'industrial-engineer'],
    atsKeywords: ['preventive maintenance', 'PM program', 'CMMS', 'predictive maintenance', 'equipment maintenance', 'maintenance scheduling', 'work orders', 'Maximo', 'SAP PM', 'vibration analysis', 'oil analysis', 'maintenance management'],
