    professionSlugs: ['wind-turbine-technician', 'electrician', 'electrical-engineer', 'mechanical-engineer', 'maintenance-technician', 'safety-manager'],
    atsKeywords: ['wind energy', 'wind turbine', 'wind technician', 'SCADA', 'blade repair', 'gearbox', 'pitch system', 'yaw system', 'GWO', 'turbine maintenance', 'renewable energy', 'wind farm'],
